mapper.select:
select u.user_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark from sys_user u where u.del_flag = '0'
AND u.user_id = #{userId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.status = #{status}
AND u.phonenumber like concat('%', #{phonenumber}, '%')
AND date_format(u.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')
AND date_format(u.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')
AND EXISTS ( SELECT 1 FROM sys_user_ent ue LEFT JOIN t_bas_enterprise e ON e.ent_code = ue.ent_code WHERE ue.user_id = u.user_id AND e.ent_code = #{queryEntCode} )
AND EXISTS ( SELECT 1 FROM sys_user_ent ue LEFT JOIN t_bas_enterprise e ON e.ent_code = ue.ent_code WHERE ue.user_id = u.user_id AND e.ent_code IN
#{item.entCode}
)
ORDER BY u.create_time DESC

select distinct u.user_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.status, u.create_time
from sys_user u
left join sys_user_role ur on u.user_id = ur.user_id
left join sys_role r on r.role_id = ur.role_id
where u.del_flag = '0' and r.role_id = #{roleId}

    AND u.user_name like concat('%', #{userName}, '%')


    AND u.phonenumber like concat('%', #{phonenumber}, '%')


    AND exists (select 1 from sys_user_ent where user_id = u.user_id and ent_code in

            #{item.entCode}

        )

select distinct u.user_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.status, u.create_time from sys_user u left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and (r.role_id != #{roleId} or r.role_id IS NULL) and u.user_id not in (select u.user_id from sys_user u inner join sys_user_role ur on u.user_id = ur.user_id and ur.role_id = #{roleId})
AND u.user_name like concat('%', #{userName}, '%')
AND u.phonenumber like concat('%', #{phonenumber}, '%')
AND exists (select 1 from sys_user_ent where user_id = u.user_id and ent_code in
#{item.entCode}
)

mapper.update:
update sys_user
user_name = #{userName}, nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where user_id = #{userId}

update sys_user
set status = #{status}
where user_id = #{userId}

update sys_user
set avatar = #{avatar}
where user_name = #{userName}

update sys_user
set password = #{password}
where user_name = #{userName}

mapper.delete:
update sys_user
set del_flag = '2'
where user_id = #{userId}
